// Advanced local server-like logic bank 5
// Original offline rule tables for ecosystem tuning, biome weights, spawn seeds,
// sensory AI curves, stamina pacing, nutrition classes and chunk hashing.
export const LOGIC_BANK_ID = 5;
export const RULE_PAYLOAD = ``;
export function hashRule(input) {
  let h = 2166136261 ^ LOGIC_BANK_ID;
  const s = String(input) + RULE_PAYLOAD.slice(0, 2048);
  for (let n = 0; n < s.length; n++) {
    h ^= s.charCodeAt(n);
    h = Math.imul(h, 16777619) >>> 0;
  }
  return h >>> 0;
}
export function evaluateLocalServerRule(entity, biome, tick) {
  const h = hashRule(`${entity?.kind ?? 0}:${biome}:${tick}`);
  return {
    appetite: ((h & 255) / 255),
    fear: (((h >>> 8) & 255) / 255),
    aggression: (((h >>> 16) & 255) / 255),
    migrationBias: (((h >>> 24) & 255) - 128) / 128
  };
}
